import React, { useState } from 'react';
import { anomalies } from '../data/mockData';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value);

function getSeverity(score) {
  if (score >= 0.85) return 'high';
  if (score >= 0.7) return 'medium';
  return 'low';
}

export default function Alerts() {
  const [dismissed, setDismissed] = useState(new Set());
  const [confirmed, setConfirmed] = useState(new Set());

  const activeAlerts = anomalies.filter(a => !dismissed.has(a.id));

  return (
    <div>
      <div className="page-header">
        <h1>Anomaly Alerts</h1>
        <p>
          {activeAlerts.length} flagged transaction{activeAlerts.length !== 1 ? 's' : ''} requiring review
        </p>
      </div>

      <div className="card" style={{ marginBottom: 24, padding: '16px 20px' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" strokeWidth="2">
            <circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/>
          </svg>
          <div>
            <div style={{ fontSize: 14, fontWeight: 600 }}>How Anomaly Detection Works</div>
            <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 2 }}>
              Our model analyzes your spending patterns — amount, merchant, time, and frequency — to flag transactions
              that deviate significantly from your history. Scores above 0.85 indicate high confidence anomalies.
            </div>
          </div>
        </div>
      </div>

      <div className="alerts-list">
        {activeAlerts.length === 0 && (
          <div className="card" style={{ textAlign: 'center', padding: 48 }}>
            <div style={{ fontSize: 40, marginBottom: 12 }}>All clear</div>
            <div style={{ fontSize: 16, fontWeight: 600 }}>No active alerts</div>
            <div style={{ color: 'var(--text-secondary)', fontSize: 14, marginTop: 4 }}>
              All flagged transactions have been reviewed
            </div>
          </div>
        )}

        {activeAlerts.map(alert => {
          const severity = getSeverity(alert.anomaly.score);
          const isConfirmed = confirmed.has(alert.id);

          return (
            <div key={alert.id} className={`alert-card severity-${severity}`}>
              <div className="alert-icon">
                {severity === 'high' ? (
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="var(--red)" strokeWidth="2">
                    <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>
                    <line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>
                  </svg>
                ) : (
                  <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="var(--orange)" strokeWidth="2">
                    <circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>
                  </svg>
                )}
              </div>

              <div className="alert-content">
                <h3>
                  {alert.merchant}
                  <span style={{ fontWeight: 400, color: 'var(--text-secondary)', marginLeft: 8, fontSize: 13 }}>
                    {formatCurrency(alert.amount)}
                  </span>
                </h3>
                <p>{alert.anomaly.reason}</p>
                <div className="alert-meta">
                  <span>
                    Confidence:{' '}
                    <span className={`anomaly-score ${severity === 'high' ? 'score-high' : 'score-medium'}`}>
                      {(alert.anomaly.score * 100).toFixed(0)}%
                    </span>
                  </span>
                  <span>{alert.date}</span>
                  <span>{alert.pending ? 'Pending' : 'Cleared'}</span>
                  {isConfirmed && <span style={{ color: 'var(--green)', fontWeight: 600 }}>Marked as legitimate</span>}
                </div>
              </div>

              <div className="alert-actions">
                {!isConfirmed ? (
                  <>
                    <button
                      className="btn btn-danger"
                      onClick={() => window.alert('Note to Jason: Dispute with your bank with the Plaid API.')}
                    >
                      Report Fraud
                    </button>
                    <button className="btn btn-ghost" onClick={() => setConfirmed(s => new Set(s).add(alert.id))}>
                      It's Me
                    </button>
                  </>
                ) : (
                  <button className="btn btn-ghost" onClick={() => setDismissed(s => new Set(s).add(alert.id))}>
                    Dismiss
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
